    // --- CSV EXPORT ---
    const handleExport = () => {
        const headers = ['SKU', 'Product Name', 'Category', 'Branch', 'Quantity', 'Cost Price', 'Retail Price', 'Wholesale Price', 'OEM Numbers'];

        const rows = stockItems.map(item => [
            item.product.sku,
