                        quantity: parseInt(getVal('qty') || getVal('quantity') || '0'),
                        oemNumbers: getVal('oem'),
                        description: getVal('desc')
                    });
                }
            }

            try {
                // Assume importing into the first branch found or active user's branch
                const targetBranchId = branches[0]?.id; 
                if (!targetBranchId) throw new Error("No branch available");

                await apiClient.post('/products/bulk', {
                    branchId: targetBranchId,
                    products
