/* Custom Utilities */
@layer utilities {
  .scrollbar-hide::-webkit-scrollbar {
      display: none;
  }
  .scrollbar-hide {
      -ms-overflow-style: none;
      scrollbar-width: none;
  }

  .animate-slide-up {
    animation: slideUp 0.4s ease-out;
  }

  .animate-scale-up {
    animation: scaleUp 0.3s ease-out;
  }

  .animate-fade-in {
    animation: fadeIn 0.5s ease-out;
  }

  .animate-slide-right {
    animation: slideRight 0.6s ease-out;
  }

  .animate-pulse-once {
    animation: pulseOnce 0.5s ease-in-out;
  }
}

/* Keyframes */
@keyframes slideUp {
  0% { transform: translateY(20px); opacity: 0; }
  100% { transform: translateY(0); opacity: 1; }
}

@keyframes scaleUp {
  0% { transform: scale(0.95); opacity: 0; }
  100% { transform: scale(1); opacity: 1; }
}

@keyframes fadeIn {
  0% { opacity: 0; }
  100% { opacity: 1; }
}

@keyframes slideRight {
  0% { transform: translateX(100%); }
  100% { transform: translateX(0); }
}

@keyframes pulseOnce {
  0%, 100% { transform: scale(1); }
  50% { transform: scale(1.2); }
}

/* --- PRINT STYLES --- */
@media print {
  /* Hide everything by default */
  body * {
    visibility: hidden;
  }

  /* Show only the print section */
  .print-section, .print-section * {
    visibility: visible;
  }

  /* Position the print section at the very top-left of the page */
  .print-section {
    position: fixed;
    left: 0;
    top: 0;
    width: 100%;
    margin: 0;
    padding: 20px;
    background: white;
    z-index: 99999; /* Ensure it stays on top */
  }

  /* Hide browser/app specific elements that might be stubborn */
  #root, nav, header, footer, aside, .fixed, .modal-backdrop {
    display: none !important;
  }

