```tsx
import React, { useState, useRef, useEffect } from 'react';
import { Search, Eye, Printer, FileText, Filter, Download, Loader2, ChevronLeft, ChevronRight } from 'lucide-react';
import { Sale } from '../../types';
import InvoiceTemplate from './InvoiceTemplate';
import { apiClient } from '../../utils/apiClient';

const SalesHistory: React.FC = () => {
    const [sales, setSales] = useState<Sale[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [filterDate, setFilterDate] = useState('');
    const [pagination, setPagination] = useState({ page: 1, limit: 20, total: 0, pages: 1 });

    // Print State
    const [printSale, setPrintSale] = useState<Sale | null>(null);
    const printRef = useRef<HTMLDivElement>(null);

    const fetchSales = async (page = 1) => {
        setIsLoading(true);
        try {
            const params = new URLSearchParams();
            params.append('page', page.toString());
            params.append('limit', pagination.limit.toString());
            if (searchTerm) params.append('search', searchTerm);
            if (filterDate) params.append('date', filterDate);

            const response = await apiClient.get(`/sales?${params.toString()}`);

            if (response.data.data) {
                setSales(response.data.data);
                setPagination(response.data.pagination);
            }
        } catch (error) {
            console.error("Failed to fetch sales", error);
            // Fallback mock if backend offline
            setSales([
               { id: '1', receiptNumber: 'RCP-OFFLINE-001', date: new Date().toISOString(), totalAmount: 4500, paymentMethod: 'CASH', cashierName: 'System', itemsCount: 2, kraControlCode: 'PENDING', itemsSnapshot: [] }
            ]);
        } finally {
            setIsLoading(false);
        }
    };

    useEffect(() => {
        const delay = setTimeout(() => fetchSales(1), 500);
        return () => clearTimeout(delay);
    }, [searchTerm, filterDate]);

    const handlePrint = (sale: Sale) => {
        setPrintSale(sale);
        // Short delay to allow React to render the template before printing
        setTimeout(() => {
            window.print();
            // Cleanup after print dialog closes
            // setTimeout(() => setPrintSale(null), 1000); 
        }, 300);
    };

    const handlePageChange = (newPage: number) => {
        if (newPage >= 1 && newPage <= pagination.pages) {
            fetchSales(newPage);
        }
    };

    return (
        <div className="h-full flex flex-col">
            {/* Hidden Print Template - Will become visible only during print via CSS */}
            <div className="hidden print:block">
                {printSale && <InvoiceTemplate data={printSale} type="TAX_INVOICE" ref={printRef} />}
            </div>

            <div className="flex justify-between items-center mb-6 print:hidden">
                <div>
                    <h2 className="text-2xl font-bold text-masuma-dark font-display uppercase">Sales History</h2>
                    <p className="text-sm text-gray-500">Audit trail of all POS transactions.</p>
                </div>
            </div>

            <div className="bg-white rounded-lg shadow-sm border border-gray-200 flex-1 flex flex-col overflow-hidden print:hidden">
                {/* Toolbar */}
                <div className="p-4 border-b border-gray-200 bg-gray-50 flex flex-col md:flex-row gap-4 items-center justify-between">
                     <div className="relative w-full md:w-96">
                        <Search className="absolute left-3 top-3 text-gray-400" size={18} />
                        <input 
                            type="text" 
                            className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded outline-none focus:border-masuma-orange bg-white" 
                            placeholder="Search Receipt # or Customer..." 
                            value={searchTerm}
                            onChange={e => setSearchTerm(e.target.value)}
                        />
                     </div>
                     <div className="flex items-center gap-2 w-full md:w-auto">
                         <div className="flex items-center gap-2 bg-white border border-gray-300 rounded px-3 py-2">
                             <Filter size={16} className="text-gray-400" />
                             <input 
                                type="date" 
                                className="text-sm text-gray-600 outline-none" 
                                value={filterDate}
                                onChange={(e) => setFilterDate(e.target.value)}
                             />
                         </div>
                         {filterDate && (
                            <button onClick={() => setFilterDate('')} className="text-xs text-red-500 hover:underline">Clear</button>
                         )}
                     </div>
                </div>

                {/* Table */}
                <div className="flex-1 overflow-auto">
                    {isLoading ? (
                        <div className="flex items-center justify-center h-64">
                            <Loader2 className="animate-spin text-masuma-orange" size={32} />
                        </div>
                    ) : (
                        <table className="w-full text-left">
                            <thead className="bg-white text-gray-500 uppercase font-bold text-xs border-b border-gray-200 sticky top-0 z-10 shadow-sm">
                                <tr>
                                    <th className="px-6 py-4">Receipt #</th>
                                    <th className="px-6 py-4">Date & Time</th>
                                    <th className="px-6 py-4">Customer</th>
                                    <th className="px-6 py-4">Items</th>
                                    <th className="px-6 py-4">Total (KES)</th>
                                    <th className="px-6 py-4">Payment</th>
                                    <th className="px-6 py-4">KRA Status</th>
                                    <th className="px-6 py-4 text-right">Actions</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-gray-100 text-sm">
                                {sales.map(sale => (
                                    <tr key={sale.id} className="hover:bg-gray-50 transition">
                                        <td className="px-6 py-4 font-mono font-bold text-masuma-dark">{sale.receiptNumber}</td>
                                        <td className="px-6 py-4 text-gray-500">{new Date(sale.createdAt || sale.date).toLocaleString()}</td>
                                        <td className="px-6 py-4">
                                            {sale.customerName ? (
                                                <span className="font-bold text-gray-800">{sale.customerName}</span>
                                            ) : (
                                                <span className="text-gray-400 italic">Walk-in</span>
                                            )}
                                        </td>
                                        <td className="px-6 py-4">{sale.itemsCount || (sale.itemsSnapshot?.length || 0)}</td>
                                        <td className="px-6 py-4 font-bold text-masuma-dark">{Number(sale.totalAmount).toLocaleString()}</td>
                                        <td className="px-6 py-4">
                                            <span className={`text-[10px] font-bold uppercase px-2 py-1 rounded ${
                                                sale.paymentMethod === 'CASH' ? 'bg-green-100 text-green-700' : 
                                                sale.paymentMethod === 'MPESA' ? 'bg-green-100 text-green-700' : 'bg-blue-100 text-blue-700'
                                            }`}>
                                                {sale.paymentMethod}
                                            </span>
                                        </td>
                                        <td className="px-6 py-4">
                                            {sale.kraControlCode ? (
                                                <span className="flex items-center gap-1 text-green-600 font-bold text-[10px] uppercase">
                                                    <FileText size={12} /> Signed
                                                </span>
                                            ) : (
                                                <span className="text-red-500 font-bold text-[10px] uppercase">Pending</span>
                                            )}
                                        </td>
                                        <td className="px-6 py-4 text-right">
                                            <div className="flex justify-end gap-2">
                                                <button 
                                                    onClick={() => handlePrint(sale)}
                                                    className="p-2 text-gray-400 hover:text-masuma-dark" 
                                                    title="Print Receipt"
                                                >
                                                    <Printer size={16} />
                                                </button>
                                            </div>
                                        </td>
                                    </tr>
                                ))}
                                {sales.length === 0 && (
                                    <tr>
                                        <td colSpan={8} className="text-center py-8 text-gray-500">No sales found matching your criteria.</td>
                                    </tr>
                                )}
                            </tbody>
                        </table>
                    )}
                </div>

                {/* Pagination */}
                <div className="p-4 border-t border-gray-200 bg-gray-50 flex justify-between items-center">
                    <span className="text-xs text-gray-500">
                        Showing page {pagination.page} of {pagination.pages} ({pagination.total} records)
                    </span>
                    <div className="flex gap-2">
                        <button 
                            onClick={() => handlePageChange(pagination.page - 1)}
                            disabled={pagination.page === 1}
                            className="p-2 bg-white border border-gray-300 rounded hover:bg-gray-100 disabled:opacity-50 disabled:cursor-not-allowed"
                        >
                            <ChevronLeft size={16} />
                        </button>
                        <button 
                            onClick={() => handlePageChange(pagination.page + 1)}
                            disabled={pagination.page === pagination.pages}
                            className="p-2 bg-white border border-gray-300 rounded hover:bg-gray-100 disabled:opacity-50 disabled:cursor-not-allowed"
                        >
                            <ChevronRight size={16} />
                        </button>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default SalesHistory;
```

## components/admin/ShippingManager.tsx

Added logic to print Waybills/Delivery Notes for shipping orders.

```tsx
import React, { useState, useEffect, useRef } from 'react';
import { Truck, MapPin, CheckCircle, Printer, Search, Package, Loader2, RefreshCw, AlertTriangle } from 'lucide-react';
import { apiClient } from '../../utils/apiClient';
import InvoiceTemplate from './InvoiceTemplate';

interface Shipment {
    id: string;
    orderNumber: string;
    customerName: string;
    date: string;
    total: number;
    status: string;
    items: any[];
}

const ShippingManager: React.FC = () => {
    const [shipments, setShipments] = useState<Shipment[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [activeTab, setActiveTab] = useState('PENDING'); // PENDING, PAID, SHIPPED

    // Print State
    const [printShipment, setPrintShipment] = useState<any | null>(null);
    const printRef = useRef<HTMLDivElement>(null);

    const fetchShipments = async () => {
        setIsLoading(true);
        try {
            // Fetch orders relevant to shipping
            const res = await apiClient.get(`/orders?status=${activeTab}`);
            setShipments(res.data);
        } catch (error) {
            console.error("Failed to fetch shipments", error);
        } finally {
            setIsLoading(false);
        }
    };

    useEffect(() => {
        fetchShipments();
    }, [activeTab]);

    const handleDispatch = async (id: string) => {
        try {
            await apiClient.patch(`/orders/${id}/status`, { status: 'SHIPPED' });
            fetchShipments(); 
        } catch (error) {
            alert('Failed to update status');
        }
    };

    const handlePrintWaybill = (shipment: any) => {
        setPrintShipment(shipment);
        setTimeout(() => {
            window.print();
        }, 300);
    };

    const getStatusBadge = (status: string) => {
        switch (status) {
            case 'PENDING': return <span className="bg-yellow-100 text-yellow-700 px-2 py-1 rounded text-[10px] font-bold uppercase">Processing</span>;
            case 'PAID': return <span className="bg-blue-100 text-blue-700 px-2 py-1 rounded text-[10px] font-bold uppercase">Ready for Dispatch</span>;
            case 'SHIPPED': return <span className="bg-purple-100 text-purple-700 px-2 py-1 rounded text-[10px] font-bold uppercase">In Transit</span>;
            case 'DELIVERED': return <span className="bg-green-100 text-green-700 px-2 py-1 rounded text-[10px] font-bold uppercase">Delivered</span>;
            default: return null;
        }
    };

    return (
        <div className="h-full flex flex-col">
             {/* Hidden Print Template */}
             <div className="hidden print:block">
                {printShipment && <InvoiceTemplate data={printShipment} type="WAYBILL" ref={printRef} />}
            </div>

             <div className="flex justify-between items-center mb-6 print:hidden">
                <div>
                    <h2 className="text-2xl font-bold text-masuma-dark font-display uppercase">Logistics & Dispatch</h2>
                    <p className="text-sm text-gray-500">Manage delivery queues, assign drivers, and print waybills.</p>
                </div>
                <button onClick={fetchShipments} className="p-2 bg-white border border-gray-300 rounded hover:bg-gray-50 text-gray-500">
                    <RefreshCw size={18} className={isLoading ? 'animate-spin' : ''} />
                </button>
            </div>

            {/* Tabs */}
            <div className="flex gap-4 mb-6 print:hidden">
                {['PENDING', 'PAID', 'SHIPPED'].map(status => (
                    <button 
                        key={status}
                        onClick={() => setActiveTab(status)}
                        className={`px-6 py-3 rounded-lg font-bold text-xs uppercase tracking-wider transition ${
                            activeTab === status 
                                ? 'bg-masuma-orange text-white shadow-md' 
                                : 'bg-white text-gray-500 hover:bg-gray-50 border border-gray-200'
                        }`}
                    >
                        {status === 'PAID' ? 'Ready to Ship' : status}
                    </button>
                ))}
            </div>

            <div className="bg-white rounded-lg shadow-sm border border-gray-200 flex-1 flex flex-col overflow-hidden print:hidden">
                <div className="flex-1 overflow-auto">
                    {isLoading ? (
                         <div className="flex justify-center items-center h-64">
                            <Loader2 className="animate-spin text-masuma-orange" size={32} />
                         </div>
                    ) : (
                        <table className="w-full text-left">
                            <thead className="bg-white text-gray-500 uppercase font-bold text-xs border-b border-gray-200">
                                <tr>
                                    <th className="px-6 py-4">Order Ref</th>
                                    <th className="px-6 py-4">Customer</th>
                                    <th className="px-6 py-4">Destination</th>
                                    <th className="px-6 py-4">Items</th>
                                    <th className="px-6 py-4">Status</th>
                                    <th className="px-6 py-4 text-right">Actions</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-gray-100 text-sm">
                                {shipments.map(ship => (
                                    <tr key={ship.id} className="hover:bg-gray-50">
                                        <td className="px-6 py-4 font-mono font-bold text-masuma-dark">{ship.orderNumber}</td>
                                        <td className="px-6 py-4">
                                            <div className="font-bold text-gray-800">{ship.customerName}</div>
                                            <div className="text-[10px] text-gray-500">{ship.date}</div>
                                        </td>
                                        <td className="px-6 py-4">
                                            <div className="flex items-center gap-1 text-xs text-gray-500">
                                                <MapPin size={12} /> Nairobi, Kenya (Default)
                                            </div>
                                        </td>
                                        <td className="px-6 py-4 text-xs text-gray-500">{ship.items.length} Items</td>
                                        <td className="px-6 py-4">{getStatusBadge(ship.status)}</td>
                                        <td className="px-6 py-4 text-right">
                                            <div className="flex justify-end gap-2">
                                                <button 
                                                    onClick={() => handlePrintWaybill(ship)}
                                                    className="p-1 text-gray-400 hover:text-masuma-dark" 
                                                    title="Print Waybill"
                                                >
                                                    <Printer size={16} />
                                                </button>
                                                {ship.status === 'PAID' && (
                                                    <button 
                                                        onClick={() => handleDispatch(ship.id)}
                                                        className="bg-masuma-dark text-white px-3 py-1 rounded text-[10px] font-bold uppercase hover:bg-masuma-orange transition"
                                                    >
                                                        Dispatch
                                                    </button>
                                                )}
                                            </div>
                                        </td>
                                    </tr>
                                ))}
                                {shipments.length === 0 && (
                                    <tr>
                                        <td colSpan={6} className="text-center py-12 text-gray-400">
                                            <Package size={48} className="mx-auto mb-2 opacity-20" />
                                            No shipments found in '{activeTab}' queue.
                                        </td>
                                    </tr>
                                )}
                            </tbody>
                        </table>
                    )}
                </div>
            </div>
        </div>
    );
};

export default ShippingManager;
