const bulkImportSchema = z.object({
    branchId: z.string(),
    products: z.array(z.object({
        sku: z.string(),
        name: z.string(),
        category: z.string(),
        price: z.number(),
        costPrice: z.number().optional(),
        wholesalePrice: z.number().optional(),
        description: z.string().optional(),
        oemNumbers: z.string().optional(), 
        compatibility: z.string().optional(),
        quantity: z.number().optional(),
        lowStockThreshold: z.number().optional(),
        imageUrl: z.string().optional()
    }))
});

router.post('/bulk', authenticate, authorize(['ADMIN', 'MANAGER']), validate(bulkImportSchema), async (req, res) => {
    const { branchId, products } = req.body;
    const queryRunner = AppDataSource.createQueryRunner();
    await queryRunner.connect();
    await queryRunner.startTransaction();

    try {
        const branch = await queryRunner.manager.findOneBy(Branch, { id: branchId });
        if (!branch) throw new Error('Invalid Branch ID');

        let createdCount = 0;
        let updatedCount = 0;

        for (const item of products) {
            let category = await queryRunner.manager.findOneBy(Category, { name: item.category });
            if (!category) {
                category = queryRunner.manager.create(Category, { name: item.category });
                await queryRunner.manager.save(category);
            }

            let product = await queryRunner.manager.findOneBy(Product, { sku: item.sku });

            if (product) {
                product.name = item.name;
                product.price = item.price;
                product.costPrice = item.costPrice || product.costPrice;
                product.wholesalePrice = item.wholesalePrice || product.wholesalePrice;
                product.description = item.description || product.description;
                product.category = category;
                if (item.imageUrl) product.imageUrl = item.imageUrl;
                await queryRunner.manager.save(product);
                updatedCount++;
            } else {
                product = new Product();
                product.sku = item.sku;
                product.name = item.name;
                product.price = item.price;
                product.costPrice = item.costPrice || 0;
                product.wholesalePrice = item.wholesalePrice || item.price;
                product.description = item.description || '';
                product.category = category;
                product.imageUrl = item.imageUrl || '';
                await queryRunner.manager.save(product);
                createdCount++;
            }

            if (item.oemNumbers) {
                await queryRunner.manager.delete(OemNumber, { product: { id: product.id } });
                const oems = item.oemNumbers.split(',').map((code: string) => {
                    const o = new OemNumber();
                    o.code = code.trim();
                    o.product = product!;
                    return o;
                });
                await queryRunner.manager.save(oems);
            }

            if (item.compatibility) {
                const compatStrings = item.compatibility.split(',').map(s => s.trim()).filter(s => s);
                const vehicles = [];
                for (const comp of compatStrings) {
                    const parts = comp.split(' ');
                    const make = parts.length > 1 ? parts[0] : 'Generic';
                    const model = parts.length > 1 ? parts.slice(1).join(' ') : comp;

                    let v = await queryRunner.manager.findOneBy(Vehicle, { make, model });
                    if (!v) {
                        v = queryRunner.manager.create(Vehicle, { make, model });
                        await queryRunner.manager.save(v);
                    }
                    vehicles.push(v);
                }
                product.vehicles = vehicles;
                await queryRunner.manager.save(product);
            }

            if (item.quantity !== undefined) {
                let stock = await queryRunner.manager.findOne(ProductStock, {
                    where: { product: { id: product.id }, branch: { id: branch.id } }
                });

                if (!stock) {
                    stock = new ProductStock();
                    stock.product = product;
                    stock.branch = branch;
                    stock.quantity = 0;
                }
                stock.quantity = item.quantity;
                stock.lowStockThreshold = item.lowStockThreshold || 5;
                await queryRunner.manager.save(stock);
            }
        }

        await queryRunner.commitTransaction();
        res.json({ message: 'Bulk import successful', created: createdCount, updated: updatedCount });

    } catch (error: any) {
        await queryRunner.rollbackTransaction();
        console.error(error);
        res.status(500).json({ error: error.message || 'Bulk import failed' });
    } finally {
        await queryRunner.release();
    }
});

export default router;

To fix the issue where contact details are missing from quotes and the request sometimes fails, I need to update the backend logic. Currently, when a quote is submitted via the "Special Import Request" (Sourcing Modal) or the standard Quote form, the backend creates a `Quote` entity but **fails to link it to a `Customer` entity**.

Because the `Quote` table relies on a relationship with `Customer` to store name, email, and phone, failing to create this link results in:
1.  **Missing Details:** The Quote appears in the Admin Dashboard as "Guest" or "N/A" because there is no linked customer record to pull the name/email/phone from.
2.  **Potential Errors:** If your database is strict (Non-Nullable Foreign Key), the save operation fails, causing the "Failed to send request" error on the frontend.

I will update `server/src/routes/quote.routes.ts` to:
1.  **Check** if a customer already exists with the provided email or phone.
2.  **Create** a new Customer entity if one doesn't exist.
3.  **Link** the Quote to this Customer before saving.

This ensures every quote has a valid customer attached, preserving the contact details and ensuring successful database insertion.

# Updated files:

## server/src/routes/quote.routes.ts

Updated the POST route to automatically Find or Create a Customer entity based on the input contact details, and link it to the Quote. This ensures contact info is persisted and resolves the "Guest/N/A" issue in the dashboard.

```typescript
import { Router } from 'express';
import { AppDataSource } from '../config/database';
import { Quote, QuoteStatus, QuoteType } from '../entities/Quote';
import { Customer } from '../entities/Customer'; // Import Customer Entity
import { authenticate, authorize } from '../middleware/auth';
import { validate } from '../middleware/validate';
import { z } from 'zod';
import { EmailService } from '../services/emailService';

const router = Router();
const quoteRepo = AppDataSource.getRepository(Quote);
const customerRepo = AppDataSource.getRepository(Customer);

// Schema
const createQuoteSchema = z.object({
    name: z.string().min(2),
    email: z.string().email(),
    phone: z.string().min(10),
    message: z.string().optional(),

    productId: z.string().optional(),
    productName: z.string().optional(),

    vin: z.string().min(5).optional(),
    partNumber: z.string().optional(),
    description: z.string().optional(),
    requestType: z.enum(['STANDARD', 'SOURCING']).default('STANDARD'),

    items: z.array(z.object({
        productId: z.string().optional(),
        name: z.string(),
        quantity: z.number(),
        unitPrice: z.number(),
        total: z.number()
    })).optional()
});

router.get('/', authenticate, authorize(['ADMIN', 'MANAGER']), async (req, res) => {
    try {
        const quotes = await quoteRepo.find({
            order: { createdAt: 'DESC' },
            take: 100,
            relations: ['customer']
        });

        const formatted = quotes.map(q => ({
            id: q.id,
            quoteNumber: q.quoteNumber,
            customerName: q.customer?.name || 'Guest',
            customerEmail: q.customer?.email || 'N/A',
            customerPhone: q.customer?.phone || 'N/A',
            date: q.createdAt.toLocaleDateString(),
            total: Number(q.total),
            status: q.status,
            type: q.requestType,
            vin: q.vin,
            itemsCount: q.items?.length || 0,
            items: q.items 
        }));

        res.json(formatted);
    } catch (error) {
        console.error(error);
        res.status(500).json({ error: 'Failed to fetch quotes' });
    }
});

router.post('/', validate(createQuoteSchema), async (req, res) => {
    try {
        const { name, email, phone, message, productId, productName, items, vin, partNumber, description, requestType } = req.body;

        // 1. Find or Create Customer to ensure contact details are saved
        let customer = await customerRepo.findOne({
            where: [
                { email: email },
                { phone: phone }
            ]
        });

        if (!customer) {
            customer = new Customer();
            customer.name = name;
            customer.email = email;
            customer.phone = phone;
            customer.isWholesale = false; // Default to retail
            await customerRepo.save(customer);
        }

        // 2. Create Quote
        const quote = new Quote();
        quote.quoteNumber = `QT-${Date.now().toString().slice(-6)}`;
        quote.requestType = requestType as QuoteType;
        quote.vin = vin;
        quote.customer = customer; // Link the customer!

        let quoteItems = items || [];

        if (requestType === 'SOURCING') {
            const itemName = description || 'Special Order Part';
            const details = partNumber ? `${itemName} (PN: ${partNumber})` : itemName;

            quoteItems = [{
                name: details,
                quantity: 1,
                unitPrice: 0, 
                total: 0
            }];
        } 
        else if (!items && productId && productName) {
            quoteItems = [{
                productId,
                name: productName,
                quantity: 1,
                unitPrice: 0, 
                total: 0
            }];
        }

        quote.items = quoteItems;
        quote.subtotal = 0;
        quote.tax = 0;
        quote.total = 0;
        quote.status = QuoteStatus.DRAFT;

        await quoteRepo.save(quote);

        // 3. Send Notification
        const emailBody = requestType === 'SOURCING'
            ? `Customer: ${name}\nVIN: ${vin}\nPart: ${partNumber || 'N/A'}\nDesc: ${description}`
            : `Customer: ${name}\nProduct: ${productName}\nMessage: ${message}`;

        // Fire and forget email to prevent blocking response if SMTP is slow/down
        EmailService.sendEmail('QUOTE_REQUEST', {
            name, email, phone,
            message: emailBody,
            productName: requestType === 'SOURCING' ? 'Special Sourcing' : quoteItems[0]?.name 
        }).catch(err => console.error("Background Email Error:", err));

        res.status(201).json({ message: 'Request received', quoteId: quote.id });
    } catch (error) {
        console.error("Quote Submission Error:", error);
        res.status(500).json({ error: 'Failed to submit quote' });
    }
});

const updateQuoteSchema = z.object({
    status: z.enum(['DRAFT', 'SENT', 'ACCEPTED', 'EXPIRED']).optional(),
    items: z.array(z.any()).optional(),
    total: z.number().optional()
});

router.patch('/:id', authenticate, authorize(['ADMIN', 'MANAGER']), validate(updateQuoteSchema), async (req, res) => {
    try {
        const quote = await quoteRepo.findOneBy({ id: req.params.id });
        if (!quote) return res.status(404).json({ error: 'Quote not found' });

        if (req.body.status) quote.status = req.body.status;
        if (req.body.items) quote.items = req.body.items;
        if (req.body.total !== undefined) quote.total = req.body.total;

        await quoteRepo.save(quote);
        res.json(quote);
    } catch (error) {
        res.status(500).json({ error: 'Failed to update quote' });
    }
});

export default router;

To resolve the issue of overlays (like black backgrounds, scrollbars, or other UI elements) appearing on your receipts and invoices during printing, I will implement a **Force Print Layout** strategy.

This involves:
1.  **Updating `index.css`**: Creating a rigorous `@media print` rule that hides *everything* in the browser window (including modal backdrops) and strictly shows only the specific invoice container, positioned on a clean white background.
2.  **Updating Components**: Applying this specific print class (`print-force-container`) to the invoice wrappers in `OrderDetailsModal`, `SalesHistory`, and `ShippingManager`.

Here are the changes:

