## server/src/services/mpesaService.ts

Production-ready M-Pesa logic with Token Caching (Redis), strict phone normalization, and detailed error propagation from Safaricom APIs.

```typescript
import axios from 'axios';
import { Buffer } from 'buffer';
import { AppDataSource } from '../config/database';
import { MpesaTransaction } from '../entities/MpesaTransaction';
import { Order, OrderStatus } from '../entities/Order';
import { SystemSetting } from '../entities/SystemSetting';
import { CacheService } from '../lib/cache';
import { logger } from '../utils/logger';

export class MpesaService {
  private static transactionRepo = AppDataSource.getRepository(MpesaTransaction);
  private static orderRepo = AppDataSource.getRepository(Order);
  private static settingsRepo = AppDataSource.getRepository(SystemSetting);

  // Helper to get setting with fallback to env
  private static async getSetting(key: string, envKey?: string): Promise<string> {
    const setting = await this.settingsRepo.findOneBy({ key });
    if (setting && setting.value) return setting.value;
    return (envKey && process.env[envKey]) ? process.env[envKey]! : '';
  }

  private static formatPhoneNumber(phone: string): string {
    // Remove all non-numeric characters
    let p = phone.replace(/\D/g, '');

    // Normalize to 254 format (Safaricom Requirement)
    if (p.startsWith('07') || p.startsWith('01')) {
      p = '254' + p.substring(1);
    } else if (p.startsWith('7') || p.startsWith('1')) {
        p = '254' + p;
    }

    return p;
  }

  private static async getAccessToken(): Promise<string> {
    // Use CacheService to prevent hitting Safaricom Rate Limits
    // Tokens expire in 3600s (1 hour). Cache for ~55 minutes.
    return CacheService.getOrSet('mpesa_access_token', async () => {
        const consumerKey = await this.getSetting('MPESA_CONSUMER_KEY', 'MPESA_CONSUMER_KEY');
        const consumerSecret = await this.getSetting('MPESA_CONSUMER_SECRET', 'MPESA_CONSUMER_SECRET');
        const env = process.env.MPESA_ENV || 'sandbox';
        const baseUrl = env === 'production' ? 'https://api.safaricom.co.ke' : 'https://sandbox.safaricom.co.ke';

        if (!consumerKey || !consumerSecret) {
            logger.error('M-Pesa credentials missing in Settings or Environment');
            throw new Error('M-Pesa configuration missing');
        }

        const auth = Buffer.from(`${consumerKey}:${consumerSecret}`).toString('base64');
        try {
            const response = await axios.get(`${baseUrl}/oauth/v1/generate?grant_type=client_credentials`, {
                headers: { Authorization: `Basic ${auth}` }
            });
            logger.info('M-Pesa Access Token Refreshed');
            return response.data.access_token;
        } catch (error: any) {
            logger.error('M-Pesa Auth Failed:', error.response?.data || error.message);
            throw new Error('Failed to authenticate with Safaricom. Check credentials.');
        }
    }, 3300); 
  }

  static async initiateStkPush(orderId: string, phoneNumber: string, amount: number) {
    try {
        const token = await this.getAccessToken();
        const formattedPhone = this.formatPhoneNumber(phoneNumber);
        const timestamp = new Date().toISOString().replace(/[^0-9]/g, '').slice(0, 14);

        const shortcode = await this.getSetting('MPESA_SHORTCODE', 'MPESA_SHORTCODE');
        const passkey = await this.getSetting('MPESA_PASSKEY', 'MPESA_PASSKEY');
        const callbackUrl = await this.getSetting('MPESA_CALLBACK_URL', 'MPESA_CALLBACK_URL');
        const env = process.env.MPESA_ENV || 'sandbox';
        const baseUrl = env === 'production' ? 'https://api.safaricom.co.ke' : 'https://sandbox.safaricom.co.ke';

        if (!shortcode || !passkey || !callbackUrl) {
            throw new Error('Missing M-Pesa Paybill/Callback configuration.');
        }

        const password = Buffer.from(`${shortcode}${passkey}${timestamp}`).toString('base64');

        // Standard Daraja API Payload
        const payload = {
            BusinessShortCode: shortcode,
            Password: password,
            Timestamp: timestamp,
            TransactionType: 'CustomerPayBillOnline', // Or CustomerBuyGoodsOnline for Tills
            Amount: Math.ceil(amount), 
            PartyA: formattedPhone,
            PartyB: shortcode,
            PhoneNumber: formattedPhone,
            CallBackURL: callbackUrl,
            AccountReference: `ORD-${orderId.slice(0, 5)}`, 
            TransactionDesc: `Masuma Order ${orderId.slice(0, 5)}`
        };

        logger.info(`Initiating STK Push for ${formattedPhone} - KES ${amount}`);

        const response = await axios.post(`${baseUrl}/mpesa/stkpush/v1/processrequest`, payload, {
            headers: { Authorization: `Bearer ${token}` }
        });

        // Log logic for callback tracking
        const order = await this.orderRepo.findOneBy({ id: orderId });
        if (order) {
            const tx = this.transactionRepo.create({
                order: order,
                merchantRequestID: response.data.MerchantRequestID,
                checkoutRequestID: response.data.CheckoutRequestID,
                amount: amount,
                phoneNumber: formattedPhone,
                status: 'PENDING'
            });
            await this.transactionRepo.save(tx);
        }

        logger.info(`STK Push Success: CheckoutID ${response.data.CheckoutRequestID}`);
        return response.data;

    } catch (error: any) {
        // Detailed Error Propagation
        const darajaError = error.response?.data?.errorMessage || error.message;
        logger.error('STK Push Failed:', darajaError);
        throw new Error(`M-Pesa Error: ${darajaError}`);
    }
  }

  static async handleCallback(body: any) {
    const { stkCallback } = body.Body;
    if (!stkCallback) return;

    const { CheckoutRequestID, ResultCode, ResultDesc, CallbackMetadata } = stkCallback;

    const transaction = await this.transactionRepo.findOne({
      where: { checkoutRequestID: CheckoutRequestID },
      relations: ['order']
    });

    if (!transaction) {
      logger.warn(`Callback received for unknown CheckoutID: ${CheckoutRequestID}`);
      return;
    }

    if (ResultCode === 0) {
      const items = CallbackMetadata.Item;
      const receiptItem = items.find((i: any) => i.Name === 'MpesaReceiptNumber');
      const receiptNumber = receiptItem?.Value;

      transaction.status = 'COMPLETED';
      transaction.mpesaReceiptNumber = receiptNumber;
      transaction.resultDesc = 'Payment Successful';
      await this.transactionRepo.save(transaction);

      transaction.order.status = OrderStatus.PAID;
      await this.orderRepo.save(transaction.order);

      logger.info(`✅ Payment Verified: ${receiptNumber} for Order ${transaction.order.orderNumber}`);
    } else {
      transaction.status = 'FAILED';
      transaction.resultDesc = ResultDesc;
      await this.transactionRepo.save(transaction);
      logger.warn(`❌ Payment Failed: ${ResultDesc}`);
    }
  }
}
