The "Upload failed" error is occurring because the `apiClient` is forcing the `Content-Type: application/json` header on all requests. When uploading files, the browser needs to set this header automatically to `multipart/form-data; boundary=...`. By forcing it to JSON, the backend (Multer) ignores the file data, leading to a "No file uploaded" error.

I will fix this by removing the default header configuration in `apiClient` (Axios handles this automatically) and improving the error feedback in the managers.

# Updated files:

## utils/apiClient.ts

Removed the default `Content-Type` header. Axios will now automatically set `application/json` for data objects and `multipart/form-data` for file uploads, ensuring both work correctly.

```typescript
import axios, { InternalAxiosRequestConfig } from 'axios';
import { Product, Category } from '../types';

// In production, this would be your deployed backend URL
const BASE_URL = process.env.VITE_API_URL || 'http://localhost:3000/api';

export const apiClient = axios.create({
  baseURL: BASE_URL,
  timeout: 10000, // Increased timeout for slower production networks
  // Removed explicit Content-Type header to allow Axios to set it automatically
  // (application/json for objects, multipart/form-data for FormData)
});

// --- MOCK DATA FOR OFFLINE MODE ---
const MOCK_PRODUCTS: Product[] = [
    {
        id: '1',
        name: 'Oil Filter (Spin-on)',
        sku: 'MFC-112',
        category: Category.FILTERS,
        price: 850,
        description: 'High-efficiency oil filter with anti-drain back valve.',
        compatibility: ['Toyota Corolla', 'Toyota Vitz', 'Toyota Fielder'],
        image: 'https://masuma.com/wp-content/uploads/2021/09/MFC-112_1.jpg',
        stock: true,
        oemNumbers: ['90915-10001', '90915-YZZE1']
    },
    // ... (Keeping existing mock data logic for fallback)
];

// Request Interceptor
apiClient.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem('masuma_auth_token');
    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
  },
  (error) => Promise.reject(error)
);

// Response Interceptor
apiClient.interceptors.response.use(
  (response) => response,
  async (error) => {
    // Fallback to mock data on ANY network error to ensure UI stability
    if (error.code === 'ERR_NETWORK' || error.message === 'Network Error' || !error.response) {
        console.warn('Backend unreachable. Serving Mock Data.');
        return serveMockData(error.config);
    }

    // Handle Auth Error
    if (error.response?.status === 401 && !error.config.url.includes('/login')) {
        localStorage.removeItem('masuma_auth_token');
        window.location.href = '/'; 
    }

    return Promise.reject(error);
  }
);

// --- MOCK HANDLER ---
const serveMockData = (config: InternalAxiosRequestConfig) => {
    const url = config.url || '';
    const mockHeaders = { 'x-datasource': 'mock' };

    return new Promise((resolve, reject) => {
        setTimeout(() => {
            if (url.includes('/products')) {
                // ... (Mock logic remains the same)
                resolve({ data: { data: MOCK_PRODUCTS, meta: { total: 5, page: 1, limit: 20 } }, status: 200, headers: mockHeaders });
                return;
            }
            // ... (Other mock routes)

            // Default 200 OK for POSTs (create/update)
            if (config.method !== 'get') {
                resolve({ data: { message: 'Action simulated (Offline Mode)' }, status: 200, headers: mockHeaders });
                return;
            }

            reject(new Error('Mock route not found'));
        }, 500);
    });
};

export const formatCurrency = (amount: number) => {
  return new Intl.NumberFormat('en-KE', {
    style: 'currency',
    currency: 'KES',
    minimumFractionDigits: 0,
    maximumFractionDigits: 0,
  }).format(amount);
};
