## server/src/services/saleService.ts

Update `createSale` to robustly find or create customers based on phone/name if ID is missing, ensuring sales are linked to customer profiles instead of defaulting to Walk-in.

```typescript
import { AppDataSource } from '../config/database';
import { Sale } from '../entities/Sale';
import { ProductStock } from '../entities/ProductStock';
import { User } from '../entities/User';
import { Branch } from '../entities/Branch';
import { Customer } from '../entities/Customer';
import { EtimsService } from './etimsService';

interface SaleItemDto {
  productId: string;
  name: string;
  quantity: number;
  price: number;
}

interface CreateSaleDto {
  items: SaleItemDto[];
  totalAmount: number;
  paymentMethod: string;
  branchId: string;
  cashierId: string;
  customerId?: string;
  customerName?: string; // Added fallback
  customerPhone?: string; // Added fallback
  paymentDetails?: any;
}

export class SaleService {
  static async createSale(data: CreateSaleDto) {
    const queryRunner = AppDataSource.createQueryRunner();
    await queryRunner.connect();
    await queryRunner.startTransaction();

    try {
      const taxRate = 0.16;
      const netAmount = data.totalAmount / (1 + taxRate);
      const taxAmount = data.totalAmount - netAmount;

      const sale = new Sale();
      sale.receiptNumber = `RCP-${Date.now()}-${Math.floor(Math.random() * 1000)}`;
      sale.branch = { id: data.branchId } as Branch;
      sale.cashier = { id: data.cashierId } as User;

      // --- Robust Customer Linking Logic ---
      let customer = null;

      // 1. Try ID lookup
      if (data.customerId) {
          customer = await queryRunner.manager.findOneBy(Customer, { id: data.customerId });
      }

      // 2. If no ID but Phone provided, try to find by phone or create
      if (!customer && data.customerPhone) {
          customer = await queryRunner.manager.findOneBy(Customer, { phone: data.customerPhone });

          if (!customer && data.customerName) {
              // Create new customer on the fly
              customer = new Customer();
              customer.name = data.customerName;
              customer.phone = data.customerPhone;
              customer.isWholesale = false;
              await queryRunner.manager.save(customer);
          }
      }

      // 3. Assign Result
      if (customer) {
          sale.customer = customer;
          sale.customerName = customer.name;
      } else {
          // Fallback for true walk-ins
          sale.customerName = data.customerName || 'Walk-in Customer';
      }

      sale.itemsSnapshot = data.items;
      sale.totalAmount = data.totalAmount;
      sale.netAmount = parseFloat(netAmount.toFixed(2));
      sale.taxAmount = parseFloat(taxAmount.toFixed(2));
      sale.paymentMethod = data.paymentMethod;
      sale.paymentDetails = data.paymentDetails;

      const fiscalData = await EtimsService.signInvoice(
        sale.receiptNumber, 
        data.items.map(i => ({
            hsCode: '8708.99.00',
            name: i.name,
            qty: i.quantity,
            unitPrice: i.price,
            taxRate: 16
        })),
        data.totalAmount
      );

      if (fiscalData) {
          sale.kraControlCode = fiscalData.controlCode;
          sale.kraQrCodeUrl = fiscalData.qrCode;
          sale.kraSignature = fiscalData.signature;
          sale.kraDate = fiscalData.fiscalDate;
      }

      await queryRunner.manager.save(sale);

      for (const item of data.items) {
        const stockRepo = queryRunner.manager.getRepository(ProductStock);
        const stockEntry = await stockRepo.findOne({
            where: { product: { id: item.productId }, branch: { id: data.branchId } },
            lock: { mode: 'pessimistic_write' }
        });

        if (stockEntry) {
            stockEntry.quantity = Math.max(0, stockEntry.quantity - item.quantity);
            await stockRepo.save(stockEntry);
        } else {
            const newStock = new ProductStock();
            newStock.product = { id: item.productId } as any;
            newStock.branch = { id: data.branchId } as any;
            newStock.quantity = -item.quantity;
            await stockRepo.save(newStock);
        }
      }

      await queryRunner.commitTransaction();
      return sale;

    } catch (error) {
      await queryRunner.rollbackTransaction();
      throw error;
    } finally {
      await queryRunner.release();
    }
  }
}
